// ============================================================
//  FONCTION PRINCIPALE D'INSERTION
// ============================================================

async function seedBooks() {
  console.log('\n🌍 IMSA IntelliBook — Insertion des livres africains');
  console.log('═'.repeat(55));

  let inserted = 0;
  let updated  = 0;
  let errors   = 0;

  for (const book of books) {
    try {
      // Récupérer l'ID de la catégorie
      const catResult = await pool.query(
        'SELECT id FROM categories WHERE slug = $1',
        [book.category]
      );

      if (!catResult.rows[0]) {
        console.warn(`⚠️  Catégorie introuvable : ${book.category} (livre: ${book.title})`);
        errors++;
        continue;
      }

      const categoryId = catResult.rows[0].id;
      const coverUrl   = cover(book.isbn);

      // Insérer ou mettre à jour le livre (ON CONFLICT)
      const result = await pool.query(`
        INSERT INTO books (
          legacy_id, title, author, category_id,
          isbn, year, pages, language, format,
          summary, cover_url, publisher,
          average_rating, is_new, is_featured,
          total_copies, available_copies, is_active
        ) VALUES (
          $1, $2, $3, $4,
          $5, $6, $7, $8, 'pdf',
          $9, $10, $11,
          $12, $13, $14,
          3, 3, TRUE
        )
        ON CONFLICT (legacy_id)
        DO UPDATE SET
          title           = EXCLUDED.title,
          author          = EXCLUDED.author,
          isbn            = EXCLUDED.isbn,
          cover_url       = EXCLUDED.cover_url,
          summary         = EXCLUDED.summary,
          average_rating  = EXCLUDED.average_rating,
          updated_at      = NOW()
        RETURNING id, (xmax = 0) AS is_new_row
      `, [
        book.legacy_id,
        book.title,
        book.author,
        categoryId,
        book.isbn,
        book.year,
        book.pages || null,
        book.language || 'francais',
        book.summary,
        coverUrl,
        book.publisher || null,
        book.rating || 4.0,
        book.is_new || false,
        book.is_featured || false,
      ]);

      if (result.rows[0].is_new_row) {
        inserted++;
        process.stdout.write(`✅ ${book.legacy_id} — ${book.title}\n`);
      } else {
        updated++;
        process.stdout.write(`🔄 ${book.legacy_id} — ${book.title} (mis à jour)\n`);
      }

    } catch (err) {
      console.error(`❌ Erreur pour ${book.legacy_id} — ${book.title}: ${err.message}`);
      errors++;
    }
  }

  // Mettre à jour les compteurs de livres par catégorie
  console.log('\n📊 Mise à jour des compteurs de catégories...');
  await pool.query(`
    UPDATE categories c
    SET book_count = (
      SELECT COUNT(*) FROM books b
      WHERE b.category_id = c.id AND b.is_active = TRUE AND b.deleted_at IS NULL
    )
  `);

  // Résumé final
  console.log('\n' + '═'.repeat(55));
  console.log('📚 RÉSUMÉ D\'INSERTION');
  console.log('═'.repeat(55));
  console.log(`✅ Insérés    : ${inserted} livres`);
  console.log(`🔄 Mis à jour : ${updated} livres`);
  console.log(`❌ Erreurs    : ${errors} livres`);
  console.log(`📖 Total      : ${books.length} livres traités`);

  // Vérification finale
  const countResult = await pool.query(
    'SELECT COUNT(*) AS total FROM books WHERE is_active = TRUE'
  );
  console.log(`\n🗄️  Total en base : ${countResult.rows[0].total} livres`);

  // Stats par catégorie
  const catStats = await pool.query(`
    SELECT c.name, COUNT(b.id) AS nb_livres
    FROM categories c
    LEFT JOIN books b ON b.category_id = c.id AND b.is_active = TRUE
    GROUP BY c.id, c.name
    ORDER BY c.sort_order
  `);

  console.log('\n📂 Livres par catégorie :');
  catStats.rows.forEach(row => {
    const bar = '█'.repeat(Math.floor(row.nb_livres / 2));
    console.log(`   ${row.name.padEnd(35)} ${String(row.nb_livres).padStart(3)} ${bar}`);
  });

  console.log('\n🎉 Insertion terminée ! Lance : http://localhost:5000/api/books');
  console.log('═'.repeat(55) + '\n');

  await pool.end();
}

// Lancer le script
seedBooks().catch(err => {
  console.error('\n💥 Erreur fatale :', err.message);
  console.error('   Vérifie que PostgreSQL est démarré et que le .env est correct.');
  process.exit(1);
});
